  1	import * as React from 'react';
  2	import { SummaryTable, SummaryTableRenderer } from './BaseTable';
  3	import { IRow, ISortBy } from '@patternfly/react-table';
  4	import { ListenerSummary } from '../../../types/IstioObjects';
  5	import { ActiveFilter, FILTER_ACTION_APPEND, FilterType, AllFilterTypes } from '../../../types/Filters';
  6	import { SortField } from '../../../types/SortFilters';
  7	import { Namespace } from '../../../types/Namespace';
  8	import { defaultFilter, routeLink } from '../../../helpers/EnvoyHelpers';
  9	import { Tooltip } from '@patternfly/react-core';
 10	import { PFColors } from 'components/Pf/PfColors';
 11	import { KialiIcon } from 'config/KialiIcon';
 12	import { kialiStyle } from 'styles/StyleUtils';
 13	import { SortableTh } from 'components/Table/SimpleTable';
 14	
 15	export class ListenerTable implements SummaryTable {
 16	  namespace: string;
 17	  namespaces: Namespace[];
 18	  routeLinkHandler: () => void;
 19	  sortingDirection: 'asc' | 'desc';
 20	  sortingIndex: number;
 21	  summaries: ListenerSummary[];
 22	  workload: string | undefined;
 23	
 24	  constructor(
 25	    summaries: ListenerSummary[],
 26	    sortBy: ISortBy,
 27	    namespaces: Namespace[],
 28	    namespace: string,
 29	    workload: string | undefined,
 30	    routeLinkHandler: () => void
 31	  ) {
 32	    this.summaries = summaries;
 33	    this.sortingIndex = sortBy.index ?? 0;
 34	    this.sortingDirection = sortBy.direction ?? 'asc';
 35	    this.namespaces = namespaces;
 36	    this.namespace = namespace;
 37	    this.workload = workload;
 38	    this.routeLinkHandler = routeLinkHandler;
 39	  }
 40	
 41	  availableFilters = (): FilterType[] => {
 42	    return [
 43	      {
 44	        category: 'Address',
 45	        placeholder: 'Address',
 46	        filterType: AllFilterTypes.text,
 47	        action: FILTER_ACTION_APPEND,
 48	        filterValues: []
 49	      },
 50	      {
 51	        category: 'Port',
 52	        placeholder: 'Port',
 53	        filterType: AllFilterTypes.text,
 54	        action: FILTER_ACTION_APPEND,
 55	        filterValues: []
 56	      },
 57	      {
 58	        category: 'Match',
 59	        placeholder: 'Match',
 60	        filterType: AllFilterTypes.text,
 61	        action: FILTER_ACTION_APPEND,
 62	        filterValues: []
 63	      },
 64	      {
 65	        category: 'Destination',
 66	        placeholder: 'Destination',
 67	        filterType: AllFilterTypes.text,
 68	        action: FILTER_ACTION_APPEND,
 69	        filterValues: []
 70	      }
 71	    ];
 72	  };
 73	
 74	  filterMethods = (): { [filter_id: string]: (entry: ListenerSummary, filter: ActiveFilter) => boolean } => {
 75	    return {
 76	      Address: (entry: ListenerSummary, filter: ActiveFilter): boolean => {
 77	        return entry.address.includes(filter.value);
 78	      },
 79	      Port: (entry: ListenerSummary, filter: ActiveFilter): boolean => {
 80	        return entry.port.toString().includes(filter.value);
 81	      },
 82	      Match: (entry: ListenerSummary, filter: ActiveFilter): boolean => {
 83	        return entry.match.includes(filter.value);
 84	      },
 85	      Destination: (entry: ListenerSummary, filter: ActiveFilter): boolean => {
 86	        return entry.destination.includes(filter.value);
 87	      }
 88	    };
 89	  };
 90	
 91	  sortFields = (): SortField<ListenerSummary>[] => {
 92	    return [
 93	      {
 94	        id: 'address',
 95	        title: 'Address',
 96	        isNumeric: false,
 97	        param: 'addess',
 98	        compare: (a, b) => {
 99	          return a.address.localeCompare(b.address);
100	        }
101	      },
102	      {
103	        id: 'port',
104	        title: 'Port',
105	        isNumeric: true,
106	        param: 'port',
107	        compare: (a, b) => {
108	          return a.port - b.port;
109	        }
110	      },
111	      {
112	        id: 'match',
113	        title: 'Match',
114	        isNumeric: false,
115	        param: 'match',
116	        compare: (a, b) => {
117	          return a.match.localeCompare(b.match);
118	        }
119	      },
120	      {
121	        id: 'destination',
122	        title: 'Destination',
123	        isNumeric: false,
124	        param: 'destination',
125	        compare: (a, b) => {
126	          return a.destination.localeCompare(b.destination);
127	        }
128	      }
129	    ];
130	  };
131	
132	  head = (): SortableTh[] => {
133	    return [
134	      {
135	        title: 'Address',
136	        sortable: true,
137	        info: {
138	          tooltip: (
139	            <div className={kialiStyle({ textAlign: 'left' })}>
140	              The address that the listener should listen on. In general, the address must be unique, though that is
141	              governed by the bind rules of the OS
142	            </div>
143	          )
144	        }
145	      },
146	      {
147	        title: 'Port',
148	        sortable: true
149	      },
150	      {
151	        title: 'Match',
152	        sortable: true
153	      },
154	      {
155	        title: 'Destination',
156	        sortable: true,
157	        info: {
158	          tooltip: (
159	            <div className={kialiStyle({ textAlign: 'left' })}>
160	              Original destination listener filter reads the SO_ORIGINAL_DST socket option set when a connection has
161	              been redirected by an iptables REDIRECT target, or by an iptables TPROXY target in combination with
162	              setting the listener’s transparent option
163	            </div>
164	          )
165	        }
166	      }
167	    ];
168	  };
169	
170	  resource = (): string => 'listeners';
171	
172	  setSorting = (columnIndex: number, direction: 'asc' | 'desc'): void => {
173	    this.sortingDirection = direction;
174	    this.sortingIndex = columnIndex;
175	  };
176	
177	  sortBy = (): ISortBy => {
178	    return {
179	      index: this.sortingIndex,
180	      direction: this.sortingDirection
181	    };
182	  };
183	
184	  tooltip = (): React.ReactNode => {
185	    return (
186	      <Tooltip
187	        content={
188	          <div className={kialiStyle({ textAlign: 'left' })}>
189	            Network location that can be connected to by downstream clients (Incomming to envoy). List of
190	            endpoints:ports that envoy lets traffic
191	          </div>
192	        }
193	      >
194	        <KialiIcon.Help className={kialiStyle({ width: '14px', height: '14px', color: PFColors.Info })} />
195	      </Tooltip>
196	    );
197	  };
198	
199	  rows(): IRow[] {
200	    return this.summaries
201	      .filter((value: ListenerSummary) => {
202	        return defaultFilter(value, this.filterMethods());
203	      })
204	      .sort((a: ListenerSummary, b: ListenerSummary) => {
205	        const sortField = this.sortFields().find((value: SortField<ListenerSummary>): boolean => {
206	          return value.id === this.sortFields()[this.sortingIndex].id;
207	        });
208	
209	        return this.sortingDirection === 'asc' ? sortField!.compare(a, b) : sortField!.compare(b, a);
210	      })
211	      .map(
212	        (summary: ListenerSummary): IRow => {
213	          return {
214	            cells: [
215	              summary.address,
216	              summary.port,
217	              summary.match,
218	              routeLink(summary.destination, this.namespace, this.workload, this.routeLinkHandler)
219	            ]
220	          };
221	        }
222	      );
223	  }
224	}
225	
226	export const ListenerSummaryTable = SummaryTableRenderer<ListenerTable>();

